import java.security.*; import java.util.Base64; import java.io.File; import java.nio.file.Files; public class GenerateKeys { public static void main(String[] args) throws Exception { KeyPairGenerator generator = KeyPairGenerator.getInstance("RSA"); generator.initialize(2048); KeyPair pair = generator.generateKeyPair(); PrivateKey privateKey = pair.getPrivate(); PublicKey publicKey = pair.getPublic(); File dir = new File("identity-service/src/main/resources/keys"); dir.mkdirs(); Files.write(new File(dir, "private_key.pem").toPath(), ("-----BEGIN PRIVATE KEY-----\n" + Base64.getMimeEncoder(64, new byte[]{'\n'}).encodeToString(privateKey.getEncoded()) + "\n-----END PRIVATE KEY-----\n").getBytes()); Files.write(new File(dir, "public_key.pem").toPath(), ("-----BEGIN PUBLIC KEY-----\n" + Base64.getMimeEncoder(64, new byte[]{'\n'}).encodeToString(publicKey.getEncoded()) + "\n-----END PUBLIC KEY-----\n").getBytes()); System.out.println("Keys generated"); } }
